import React from 'react';
import { Link } from 'react-router-dom';

export default function TaskCard({ task, onToggle, onDelete }) {
  const priorityBadge =
    task.priority === 'High'
      ? 'border-red-500/40 text-red-300'
      : task.priority === 'Medium'
      ? 'border-amber-500/40 text-amber-300'
      : 'border-emerald-500/40 text-emerald-300';

  const isCompleted = task.status === 'Completed';
  const statusBg = isCompleted ? 'bg-emerald-950/40' : 'bg-sky-950/40';
  const statusBorder = isCompleted ? 'border-emerald-500/40' : 'border-sky-500/40';

  return (
    <div className={`glass-card p-4 ${statusBg} ${statusBorder}`}>
      <div className="flex flex-col gap-3">
        <div className="flex justify-between items-start">
          <h3 className="font-semibold text-lg leading-tight text-white">{task.title}</h3>
          <span className={`text-xs px-2 py-1 rounded-full border ${priorityBadge}`}>{task.priority}</span>
        </div>
        {task.description && (
          <p className="text-sm text-gray-300 line-clamp-3">{task.description}</p>
        )}
        <div className="flex items-center justify-between text-xs text-gray-400">
          <div>Due: {task.dueDate ? new Date(task.dueDate).toLocaleDateString() : '—'}</div>
          <div className={`font-medium ${task.status === 'Completed' ? 'text-emerald-300' : 'text-gray-300'}`}>
            {task.status}
          </div>
        </div>
        <div className="flex gap-2 pt-1">
          <button onClick={() => onToggle(task)} className="nav-btn btn-secondary">
            Mark {task.status === 'Completed' ? 'Pending' : 'Completed'}
          </button>
          <Link to={`/tasks/${task._id}/edit`} className="nav-btn btn-secondary">
            Edit
          </Link>
          <button onClick={() => onDelete(task)} className="nav-btn btn-secondary text-red-300 border-red-500/40">
            Delete
          </button>
        </div>
      </div>
    </div>
  );
}
